import React, { useEffect, useState, useCallback, lazy, Suspense } from 'react'
import { TreeViewRelationship } from '@fs/zion-icon'
import { ListItem, useStatusOverlay, Skeleton } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { trackEvent } from '@fs/zion-analytics'
// TODO: figure out if we can dynamically import zion-relationship-viewer here. Because ViewRelationshipAllOptedInView.js is doing a dynamic import
// of it. and if we do a regular static import here, we are most likely losing the benefits of dynamic importing over in ViewRelationshipAllOptedInView.js
/* eslint-disable-next-line @nx/enforce-module-boundaries -- ignoring for now, and making a note to potentially fix in the future */
import { useRelationship } from '@fs/zion-relationship-viewer'
import useSetViewRelationshipStates from './useSetViewRelationshipStates'
import useSetRelationshipDescriptionAndPortrait from './useSetRelationshipDescriptionAndPortrait'
import useRelationshipReducer, { resetUserOptInCache } from './useRelationshipReducer'

const ErrorStateView = lazy(() => import('./views/ViewRelationshipErrorStateView'))
const ContactOptedOutView = lazy(() => import('./views/ViewRelationshipContactOptedOutView'))
const UserOptedOutView = lazy(() => import('./views/ViewRelationshipUserOptedOutView'))
const AllOptedInView = lazy(() => import('./views/ViewRelationshipAllOptedInView'))

let contactOptInStatusTempCache = {}
const setContactOptInStatusTempCache = ({ cisId, cpUserId }, newContactCache) => {
  contactOptInStatusTempCache[cisId || cpUserId] = newContactCache
}
// For testing only
export function clearTempCache() {
  resetUserOptInCache()
  contactOptInStatusTempCache = {}
}

function track(value, target) {
  const metric = { link_name: `PersonContactCard:${value}` }
  if (target) {
    metric.link_obj = target
  }
  trackEvent(metric)
}

function useShowStatusOverlay() {
  const showStatusOverlayInit = useStatusOverlay()
  const showStatusOverlay = useCallback((params) => showStatusOverlayInit(params), [showStatusOverlayInit])
  const [showStatusParams, setShowStatusParams] = useState()

  useEffect(() => {
    if (showStatusParams) {
      showStatusOverlay(showStatusParams)
      setShowStatusParams(null)
    }
  }, [showStatusParams, showStatusOverlay])

  return setShowStatusParams
}

export default function ViewRelationshipButton({ relationshipDescriptionChange, contact, overlay }) {
  const { t } = useTranslation()
  const setShowStatusParams = useShowStatusOverlay()
  const [{ userOptedInTempCache, userStatus, contactStatus }, dispatchRelationshipViewingStatus] =
    useRelationshipReducer()
  const id = contact?.cisId || contact?.cpUserId
  const idType = (contact?.cisId && 'cisId') || contact.cpUserId || 'contributorId'
  const relationshipData = useRelationship({
    relationshipType: idType,
    toId: id,
    optedIn: userStatus.isOptedIn === true,
  })
  useSetViewRelationshipStates({
    overlay,
    contact,
    userStatus,
    contactStatus,
    dispatchRelationshipViewingStatus,
    userOptedInTempCache,
    contactOptInStatusTempCache,
    setContactOptInStatusTempCache,
  })
  const [relationshipDescription, portraitUrl] = useSetRelationshipDescriptionAndPortrait(relationshipData || {})

  useEffect(() => {
    relationshipDescriptionChange({ relationshipDescription, portraitUrl })
  }, [relationshipDescription, portraitUrl, relationshipDescriptionChange])

  if (userStatus.isOptedIn === false)
    return (
      <Suspense fallback="">
        <UserOptedOutView
          setShowStatusParams={setShowStatusParams}
          dispatchRelationshipViewingStatus={dispatchRelationshipViewingStatus}
          track={track}
        />
      </Suspense>
    )

  if (contactStatus.isPending)
    return (
      <ListItem
        primaryText={t('relation-view.is-pending', 'Request pending')}
        startElement={<ListItem.Icon Icon={TreeViewRelationship} />}
      />
    )

  if (contactStatus.isOptedIn === false)
    return (
      <Suspense fallback="">
        <ContactOptedOutView
          setShowStatusParams={setShowStatusParams}
          dispatchRelationshipViewingStatus={dispatchRelationshipViewingStatus}
          contact={contact}
          track={track}
          setContactOptInStatusTempCache={setContactOptInStatusTempCache}
        />
      </Suspense>
    )

  if (userStatus.isOptedIn && contactStatus.isOptedIn && relationshipData)
    return (
      <Suspense fallback="">
        <AllOptedInView
          contact={contact}
          relationshipData={relationshipData}
          relationshipDescription={relationshipDescription}
        />
      </Suspense>
    )

  if (userStatus.isError || contactStatus.isError)
    return (
      <Suspense fallback="">
        <ErrorStateView
          setShowStatusParams={setShowStatusParams}
          dispatchRelationshipViewingStatus={dispatchRelationshipViewingStatus}
        />
      </Suspense>
    )

  return <Skeleton.ListItem hasIcon />
}
