import React from 'react'
import { useTranslation } from 'react-i18next'
import { SocialEmail, SocialCall } from '@fs/zion-icon'
import { PersonBlock, Ellipsis, List, ListItem, Separator, Skeleton } from '@fs/zion-ui'
import { css } from '@linaria/core'

const contactOverlayMinWidthCss = css`
  min-width: 340px;
`

const listPaddingCss = css`
  padding: 0 12px;
`

const fullWidthRestraintCss = css`
  max-width: calc(100vw - 24px);
`

function Location({ countryName, stateOrProvinceName }) {
  const { t } = useTranslation()

  if (countryName && stateOrProvinceName) {
    return <>{t('contact.location', '{stateOrProvinceName}, {countryName}', { countryName, stateOrProvinceName })}</>
  }
  if (countryName || stateOrProvinceName) {
    return (
      <>
        {countryName}
        {stateOrProvinceName}
      </>
    )
  }
  return null
}

export function ContactPersonBlock({
  contactName,
  portraitUrl,
  contactId,
  countryName,
  stateOrProvinceName,
  contactLoading,
}) {
  if (contactName) {
    return (
      <>
        <Separator size="xxs" />
        <div className={fullWidthRestraintCss}>
          <PersonBlock
            avatarProps={{
              monogram: contactName[0],
              src: portraitUrl,
            }}
            size="lg"
            avatarSize="bigger"
            name={<Ellipsis>{contactName}</Ellipsis>}
            details={
              <>
                <Ellipsis>@{contactId}</Ellipsis>
                <Location countryName={countryName} stateOrProvinceName={stateOrProvinceName} />
              </>
            }
            centered
          />
        </div>
        <Separator size="xxs" />
      </>
    )
  }
  if (contactLoading) {
    return <Skeleton.PersonBlock size="xl" centered />
  }
  return null
}

export function ContactInfo({ email, phoneNumber, children, contactLoading, hideContactInfo }) {
  const { t } = useTranslation()
  if (hideContactInfo) {
    return <div className={listPaddingCss}>{children}</div>
  }
  if (email || phoneNumber) {
    return (
      <div className={listPaddingCss}>
        <List>
          {children}
          {email && (
            <ListItem
              to={`mailto:${email}`}
              primaryText={<Ellipsis>{email}</Ellipsis>}
              startElement={<ListItem.Icon Icon={SocialEmail} />}
              aria-label={t('a11y.email', 'click to email {email}', { email })}
              external
            />
          )}
          {phoneNumber && (
            <ListItem
              to={`tel:${phoneNumber.includes('+') ? '' : '+'}${phoneNumber.replace(/ /g, '')}`}
              primaryText={<Ellipsis>{phoneNumber}</Ellipsis>}
              startElement={<ListItem.Icon Icon={SocialCall} />}
              aria-label={t('a11y.call', 'click to call {phoneNumber}', { phoneNumber })}
              external
            />
          )}
        </List>
      </div>
    )
  }
  if (contactLoading) {
    return <Skeleton.ListItem hasIcon />
  }
  return <div className={listPaddingCss}>{children}</div>
}

export function ContactOverlayMinWidth() {
  return <div className={contactOverlayMinWidthCss} />
}
