import axios from '@fs/zion-axios'

const relationshipDataUrlCisId = (cisId) => `/service/tree/tree-data/user-relationship/with-cis-id/${cisId}`
const relationshipDataUrlPersonId = (cpUserId) =>
  `/service/tree/tree-data/user-relationship/with-contributor-id/${cpUserId}`
export default async function getRelationshipToUser({ cisId, cpUserId }) {
  const url = cisId ? relationshipDataUrlCisId(cisId) : relationshipDataUrlPersonId(cpUserId)
  try {
    const { data } = await axios.get(url)
    return data
  } catch (error) {
    // when one or both users are not opted into relationship viewing a 403 is sent.
    if (error.request.status !== 403) {
      console.error(error)
    }
    return null
  }
}

export async function getUserRelationshipViewingOptInStatus() {
  try {
    const { status } = await axios.get('/service/tree/tree-data/user-relationship/opt-in-status')
    return { isOptedIn: status === 200 }
  } catch (error) {
    console.error(error)
    return null
  }
}

const optInStatusUrlCisId = (cisId) => `/service/tree/tree-data/user-relationship/opt-in-status/with-cis-id/${cisId}`
const optInStatusUrlCpUserId = (cpUserId) =>
  `/service/tree/tree-data/user-relationship/opt-in-status/with-contributor-id/${cpUserId}`
export async function getUserRelationshipViewingOptInStatusWithId({ cisId, cpUserId }) {
  try {
    const response = await axios.get(
      (cisId && optInStatusUrlCisId(cisId)) || (cpUserId && optInStatusUrlCpUserId(cpUserId))
    )
    const optInStatus = { isOptedIn: response.status === 200 }
    if (response.status === 204) {
      optInStatus.isPending = response.headers['invite-pending'] === 'true'
    }
    return optInStatus
  } catch (error) {
    console.error(error)
    return null
  }
}

const optInChangeStatusUrl = '/service/tree/tree-data/user-relationship/opt-in'
export async function setUsersRelationshipViewingStatus(isOptingIn) {
  try {
    const { status } = isOptingIn ? await axios.post(optInChangeStatusUrl) : await axios.delete(optInChangeStatusUrl)
    if (isOptingIn && status !== 200) {
      throw new Error(
        `setUsersRelationshipViewingStatus: request failed with status: ${status} and param isOptingIn: ${isOptingIn}`
      )
    }
    if (!isOptingIn && status !== 204) {
      throw new Error(
        `setUsersRelationshipViewingStatus: request failed with status: ${status} and param isOptingIn: ${isOptingIn}`
      )
    }
    return true
  } catch (error) {
    console.error(error)
    return false
  }
}

const requestPendingCisIdUrl = (cisId, sendNotification) =>
  `/service/tree/tree-data/user-relationship/invite-pending${sendNotification ? '-message' : ''}/with-cis-id/${cisId}`
const requestPendingCpUserIdUrl = (cpUserId, sendNotification) =>
  `/service/tree/tree-data/user-relationship/invite-pending${
    sendNotification ? '-message' : ''
  }/with-contributor-id/${cpUserId}`
export async function setUserRequestPendingStatus({ cisId, cpUserId, sendNotification = false }) {
  try {
    const { status } = await axios.put(
      cisId ? requestPendingCisIdUrl(cisId, sendNotification) : requestPendingCpUserIdUrl(cpUserId, sendNotification)
    )
    if (status !== 204) {
      throw new Error(`setUserRequestPendingStatus: request failed with status: ${status}`)
    }
    return true
  } catch (error) {
    console.error(error)
    return false
  }
}

export async function addContact(cisId) {
  return axios.post(`/service/tree/tree-data/user-relationship/friends?friendCisId=${cisId}`)
}

export async function getFriendsIds() {
  const friendsData = await axios.get('/service/tree/tree-data/user-relationship/friends/ids')
  return friendsData?.data?.friendCisIds
}

export async function removeContact(cisId) {
  return axios.delete(`/service/tree/tree-data/user-relationship/friends?friendCisId=${cisId}`)
}
