import { useEffect, useState } from 'react'
import axios from '@fs/zion-axios'
import { getSessionId } from '@fs/zion-session'

const addSessionId = (oldPortraitUrl) => {
  try {
    const sessionId = getSessionId()
    const portraitUrl = new URL(oldPortraitUrl)
    portraitUrl.searchParams.append('sessionId', sessionId)
    return portraitUrl.toString()
  } catch (err) {
    return oldPortraitUrl
  }
}
/**
 * Request data. Switch between endpoints, based on what relationshipType is provided.
 *
 * @param {object} options - all configuration for useRelationship hook.
 * @param {string} options.relationshipType - The type of ID for toId.
 * @param {string} options.toId - The ID to navigate to.
 * @param {string} options.fromId - The ID to navigate from (NOT YET IMPLEMENTED).
 * @param {object} options.eventInfo - The event specific information for use at RootsTech or other relatives around me events.
 * @param {boolean} options.hidePortraits - do not show portraits
 * @param {boolean} options.optedIn - if the user is explicitly opted in to relationship viewing. Setting this to false will prevent us from making a call to the back-end, and the hook will update whenever this is changed.
 * @returns {object} - An object including the relationship data, or if there is no relationship, or if there was an error in fetching the data. We requested that we get our data back in layers of generations rather than as a straight path.
 */
export default function useRelationship({
  relationshipType,
  toId,
  fromId,
  eventInfo,
  friendRelationship,
  hidePortraits,
  optedIn,
}) {
  // the initial value needs to be null so that we know inside
  // the RelationshipViewer if we are in an active or passive mode.
  const [data, setData] = useState(null)
  const portraitsParam = hidePortraits ? '' : 'showPortraits=true'
  const friendParam = friendRelationship ? 'friendRelationship=true' : ''
  const combinedParams =
    portraitsParam && friendParam ? `${portraitsParam}&${friendParam}` : portraitsParam || friendParam

  useEffect(() => {
    if (optedIn === false) {
      return setData({ userHasNotOptedIn: true, errorWithRelationship: true })
    }
    if (toId) {
      let isCurrent = true
      let relationshipTypeEndpoint
      switch (relationshipType) {
        case 'cisId':
          relationshipTypeEndpoint = `/service/tree/tree-data/user-relationship/v2/with-cis-id/${toId}?${combinedParams}`
          break
        case 'contributorId':
          relationshipTypeEndpoint = `/service/tree/tree-data/user-relationship/v2/with-contributor-id/${toId}?${combinedParams}`
          break
        default:
          relationshipTypeEndpoint = `/service/tree/tree-data/user-relationship/v2/person/${toId}?${combinedParams}&enforceTemplePolicyEx=true`
      }

      if (eventInfo?.eventId) {
        const { eventId, kinshipDescriptor, commonAncestorId, commonAncestorCoparentId } = eventInfo
        const kinshipParam = kinshipDescriptor ? `&kinshipDescriptor=${kinshipDescriptor}` : ''
        const commonAncestorParam = commonAncestorId ? `&hintCommonAncestorId=${commonAncestorId}` : ''
        const commonAncestorCoparentParam = commonAncestorCoparentId
          ? `&hintCommonAncestorId=${commonAncestorCoparentId}`
          : ''
        relationshipTypeEndpoint += `&conferenceUuid=${eventId}${kinshipParam}${commonAncestorParam}${commonAncestorCoparentParam}`
      }

      axios
        .get(relationshipTypeEndpoint)
        .then((resp) => {
          if (!isCurrent) return undefined
          if (resp.status === 200 && resp.data) {
            const closeRelative = resp.data.targetPerson?.relationshipToPrevious === 'CLOSE_RELATIVE'
            const displayMonogram = relationshipType === 'cisId'

            // TF-3679 - these portraitUrls are on an sg subdomain so we have to pass the sessionId
            const generations = resp.data.generations?.map?.((gen, i) => {
              gen.index = i
              if (gen?.apex?.person?.portraitUrl) {
                gen.apex.person.portraitUrl = addSessionId(gen.apex.person.portraitUrl)
              }
              if (gen?.descendingSide?.person?.portraitUrl) {
                gen.descendingSide.person.portraitUrl = addSessionId(gen.descendingSide.person.portraitUrl)
              }
              if (gen?.ascendingSide?.person?.portraitUrl) {
                gen.ascendingSide.person.portraitUrl = addSessionId(gen.ascendingSide.person.portraitUrl)
              }
              return gen
            })
            return setData({ ...resp.data, closeRelative, displayMonogram, generations })
          }
          // 204: NO RELATIONSHIP FOUND
          if (resp.status === 204) {
            return setData({ noRelationship: true, data: resp.data })
          }
          throw new Error()
        })
        .catch((error) => {
          if (!isCurrent) return undefined
          if (error.response?.status === 403) {
            return setData({ userHasNotOptedIn: true, errorWithRelationship: true })
          }
          return setData({ errorWithRelationship: true })
        })

      return () => {
        isCurrent = false
      }
    }
    return undefined
  }, [toId, fromId, relationshipType, eventInfo, hidePortraits, friendRelationship, combinedParams, optedIn])

  return data
}
