// cis.proc = refers to a process or system or service user - these are programatic processes that do work that is outside the scope of a given user request
// cis.wkca = is a Tree Well Known Contributor.  There are a couple dozen of these, such as Familysearch Admin.

export default function isFamilySearch(cisId) {
  return cisId?.includes('cis.wkca') || cisId?.includes('cis.proc')
}
