import { useEffect } from 'react'
import { trackEvent as zionTrackEvent } from '@fs/zion-analytics'

export function track(value, target) {
  const metric = { link_name: `PersonContactCard:${value}` }
  if (target) {
    metric.link_obj = target
  }
  zionTrackEvent(metric)
}

export const trackEvent = (eventTrackingString) => (event) => track(eventTrackingString, event.target)

export default function useContactAnalytics(overlay) {
  useEffect(() => {
    if (!overlay.isOpen && overlay.transitioning) {
      track('overlay:closed')
      // checking for transitioning so that it doesn't run more than once
    } else if (overlay.isOpen && overlay.transitioning) {
      track('overlay:open')
    }
  }, [overlay.isOpen, overlay.transitioning])
}
