import React from 'react'
import zionDebug from '@fs/zion-debug'
import ContactOverlayView from './ContactOverlayView'
import { useContactData } from '../ContactHooks'

const debug = zionDebug('contactOverlay')

export default function ContactOverlayDynamicData({ passedInContactData, overlay, portraitUrl, ...props }) {
  const contact = useContactData({ passedInContactData, portraitUrl, overlay })
  debug('Contact data:', contact)
  return <ContactOverlayView contact={contact} overlay={overlay} {...props} />
}
