import { useReducer } from 'react'

export const relationshipStatusOptions = {
  userOptIn: 'userOptIn',
  userOptOut: 'userOptOut',
  userOptStatusUnknown: 'userOptStatusUnknown',

  contactOptIn: 'contactOptIn',
  contactOptOut: 'contactOptOut',
  contactOptOutAndPending: 'contactOptOutAndPending',
  contactOptStatusUnknown: 'contactOptStatusUnknown',

  resetErrors: 'resetErrors',
}

let userOptedInTempCache = null

// For tests only.
export function resetUserOptInCache() {
  userOptedInTempCache = null
}

function generateRelationshipViewingStatusReducer(status, action) {
  switch (action) {
    case relationshipStatusOptions.userOptIn: {
      userOptedInTempCache = { isOptedIn: true }
      return { ...status, userStatus: { isOptedIn: true, isSet: true, isError: false } }
    }
    case relationshipStatusOptions.userOptOut: {
      userOptedInTempCache = { isOptedIn: false }
      return { ...status, userStatus: { isOptedIn: false, isSet: true, isError: false } }
    }
    case relationshipStatusOptions.userOptStatusUnknown: {
      return { ...status, userStatus: { isSet: false, isError: true } }
    }

    case relationshipStatusOptions.contactOptIn: {
      return { ...status, contactStatus: { isOptedIn: true, isPending: false, isSet: true, isError: false } }
    }
    case relationshipStatusOptions.contactOptOut: {
      return { ...status, contactStatus: { isOptedIn: false, isPending: false, isSet: true, isError: false } }
    }
    case relationshipStatusOptions.contactOptOutAndPending: {
      return { ...status, contactStatus: { isOptedIn: false, isPending: true, isSet: true, isError: false } }
    }
    case relationshipStatusOptions.contactOptStatusUnknown: {
      return { ...status, contactStatus: { isSet: false, isError: true } }
    }

    case relationshipStatusOptions.resetErrors: {
      const userStatus = status.userStatus.isError ? { isSet: false } : status.userStatus
      const contactStatus = status.contactStatus.isError ? { isSet: false } : status.contactStatus
      return { ...status, userStatus, contactStatus }
    }

    default: {
      throw new Error(`Status type ${action} Unknown in reducer function generateRelationshipViewingStatusReducer`)
    }
  }
}

export default function useRelationshipReducer() {
  const [{ userStatus, contactStatus }, dispatchRelationshipViewingStatus] = useReducer(
    generateRelationshipViewingStatusReducer,
    {
      userStatus: { isSet: false },
      contactStatus: { isSet: false },
    }
  )

  return [{ userOptedInTempCache, userStatus, contactStatus }, dispatchRelationshipViewingStatus]
}
