import { useEffect } from 'react'
import {
  getUserRelationshipViewingOptInStatus,
  getUserRelationshipViewingOptInStatusWithId,
} from '@fs/zion-relationship-service'
import { relationshipStatusOptions } from './useRelationshipReducer'

async function attemptGetUserStatus({ dispatchStatusCallback, userOptedInTempCache }) {
  const response = userOptedInTempCache ?? (await getUserRelationshipViewingOptInStatus())

  if (response.isOptedIn === true) dispatchStatusCallback(relationshipStatusOptions.userOptIn)
  if (response.isOptedIn === false) dispatchStatusCallback(relationshipStatusOptions.userOptOut)
  if (response === null) dispatchStatusCallback(relationshipStatusOptions.userOptStatusUnknown)
}

async function setContactStatus({
  dispatchStatusCallback,
  cisId,
  cpUserId,
  contactOptInStatusTempCache,
  setContactOptInStatusTempCache,
}) {
  const cachedContactOptInStatus = contactOptInStatusTempCache[cisId] || contactOptInStatusTempCache[cpUserId]
  const response = cachedContactOptInStatus ?? (await getUserRelationshipViewingOptInStatusWithId({ cisId, cpUserId }))

  setContactOptInStatusTempCache({ cisId, cpUserId }, response)

  const { isOptedIn, isPending } = response || {}

  if (response === null) dispatchStatusCallback(relationshipStatusOptions.contactOptStatusUnknown)
  if (isOptedIn === true) dispatchStatusCallback(relationshipStatusOptions.contactOptIn)
  if (isPending === true) dispatchStatusCallback(relationshipStatusOptions.contactOptOutAndPending)
  if (isOptedIn === false && isPending === false) dispatchStatusCallback(relationshipStatusOptions.contactOptOut)
}

export default function useSetViewRelationshipStates({
  overlay,
  contact,
  userStatus,
  contactStatus,
  dispatchRelationshipViewingStatus,
  userOptedInTempCache,
  contactOptInStatusTempCache,
  setContactOptInStatusTempCache,
}) {
  useEffect(() => {
    if (overlay.isOpen) {
      dispatchRelationshipViewingStatus(relationshipStatusOptions.resetErrors)
    }
  }, [overlay.isOpen, dispatchRelationshipViewingStatus])

  useEffect(() => {
    if (!userStatus.isSet && !userStatus.isError) {
      attemptGetUserStatus({
        dispatchStatusCallback: dispatchRelationshipViewingStatus,
        userOptedInTempCache,
      })
    }
  }, [userStatus.isSet, userStatus.isError, dispatchRelationshipViewingStatus, userOptedInTempCache])

  useEffect(() => {
    if (!contactStatus.isSet && !contactStatus.isError) {
      const { cisId, cpUserId } = contact
      setContactStatus({
        dispatchStatusCallback: dispatchRelationshipViewingStatus,
        cisId,
        cpUserId,
        contactOptInStatusTempCache,
        setContactOptInStatusTempCache,
      })
    }
  }, [
    contactStatus.isSet,
    contactStatus.isError,
    contact,
    contactOptInStatusTempCache,
    dispatchRelationshipViewingStatus,
    setContactOptInStatusTempCache,
  ])
}
