import { useEffect } from 'react'
import axios from '@fs/zion-axios'
import { useCache } from '@fs/zion-cache'

const cache = { storeName: 'chatRestricted' }
const initialState = {
  chatWithAnyoneRestricted: true,
  chatWithContactRestricted: true,
}

export function useChatRestricted(cisId, chatOverride) {
  const [chatRestricted, setChatRestricted] = useCache({
    cache,
    key: cisId || 'userPending',
    initialState,
  })

  useEffect(() => {
    async function checkChatRestricted() {
      setChatRestricted({
        chatWithAnyoneRestricted: await testRestriction([]),
        chatWithContactRestricted: await testRestriction([cisId]),
      })
    }
    if (cisId) checkChatRestricted()
  }, [cisId, setChatRestricted])

  if (chatOverride) return chatOverride
  return chatRestricted || initialState
}

async function testRestriction(users) {
  try {
    await axios.post('/service/fs-chat/api/v2/approval/channels/membership', { cisIds: users })
  } catch (error) {
    return true // will either be a forbidden status or a different error preventing check on restriction
  }
  return false
}
