import React from 'react'
import { useTranslation } from 'react-i18next'
import { TreeViewRelationship } from '@fs/zion-icon'
import { ListItem } from '@fs/zion-ui'
import ViewRelationshipButton from './ViewRelationshipButton'
import isFamilySearch from '../isFamilySearch'

function isNotHelper({ contactName, userLoading }) {
  return !contactName && !userLoading
}

export default function ContactRelationshipButton({
  isSelf,
  helpee,
  disableRelationshipForStorybook,
  contact,
  setRelationDisplay,
  overlay,
}) {
  const { t } = useTranslation()
  const isNotSelf = isSelf === false
  const allowMessaging = !isFamilySearch(contact?.cisId)
  const isHelper = helpee?.contactName
  const hasCisId = contact?.cisId

  if (isNotSelf && hasCisId && isNotHelper(helpee) && !disableRelationshipForStorybook && allowMessaging) {
    return (
      <ViewRelationshipButton contact={contact} relationshipDescriptionChange={setRelationDisplay} overlay={overlay} />
    )
  }
  if (isHelper) {
    return (
      <ListItem
        primaryText={t('relation-view.helper', 'Relationships Disabled While Helping')}
        startElement={<ListItem.Icon Icon={TreeViewRelationship} />}
      />
    )
  }
  return null
}
