import React from 'react'
import PropTypes from 'prop-types'
import zionDebug from '@fs/zion-debug'
import ContactOverlayView from './ContactOverlayView' // not lazy loaded because ContactOverlayDynamicData includes it as well
import isFamilySearch from '../isFamilySearch'

import ContactOverlayDynamicData from './ContactOverlayDynamicData'

const debug = zionDebug('contactOverlay')

function ContactOverlay({ contact, overlay, ...props }) {
  debug('Passed in contact data:', contact)
  const shouldDisplayPassedInData =
    contact.contactId || contact.email || contact.phoneNumber || contact.countryName || contact.stateOrProvinceName
  if ((contact.cisId || contact.cpUserId) && overlay.isOpen) {
    return (
      <>
        {shouldDisplayPassedInData || isFamilySearch(contact?.cisId) ? (
          <ContactOverlayView contact={contact} overlay={overlay} {...props} />
        ) : (
          <ContactOverlayDynamicData passedInContactData={contact} overlay={overlay} {...props} />
        )}
      </>
    )
  }
  return null
}

ContactOverlay.propTypes = {
  /** At least one id required (contact.cisId or contact.cpUserId). */
  contact: PropTypes.shape({
    cisId: PropTypes.string,
    cpUserId: PropTypes.string,
    contactName: PropTypes.string,
    contactId: PropTypes.string,
    email: PropTypes.string,
    phoneNumber: PropTypes.string,
    countryName: PropTypes.string,
    stateOrProvinceName: PropTypes.string,
  }).isRequired,
  /** An overlay object obtained from `useOverlay()` */
  overlay: PropTypes.shape({
    close: PropTypes.func,
    isOpen: PropTypes.bool,
    handleClick: PropTypes.func,
    transitioning: PropTypes.bool,
  }).isRequired,
  /** Sets url for contact portrait */
  portraitUrl: PropTypes.string,
  /** Sets the about text in the Chat message */
  aboutText: PropTypes.string,
  /** Sent the About Url in the Chat message */
  aboutUrl: PropTypes.string,
  /** If true, removes the about text from the Chat message */
  disableAbout: PropTypes.bool,
  /** If true, removes the message button */
  hideMessaging: PropTypes.bool,
  /** Fires when contact is successfully removed. */
  onContactRemoved: PropTypes.func,
}

export default ContactOverlay
