import { useState, useCallback, useEffect } from 'react'
import { useStatusOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'

export default function useContactError() {
  const { t } = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const [showMessage, setShowMessage] = useState(false)
  const setShowMessageTrue = useCallback(() => {
    setShowMessage(true)
  }, [])

  useEffect(() => {
    if (showMessage) {
      showStatusOverlay({
        message: t('contact-overlay.get-user-error', 'Unable to read contact information. Please try again later.'),
        type: 'error',
      })
      setShowMessage(false)
    }
  }, [showMessage, showStatusOverlay, t])

  return setShowMessageTrue
}
