import { useEffect, useState, useRef } from 'react'
import { useUser, useUserProfile, getCisIdFromCpUserId } from '@fs/zion-user'
import { getSessionId } from '@fs/zion-session'
import zionDebug from '@fs/zion-debug'
import { useContactError } from '.'

const debug = zionDebug('contactOverlay:useContactData')

// as of June 29 2023 this makes it so when a user views their own contact info they will see the contact information that other users would see.
// This may also make it so admin users will only see what other users see for the contact info.
// The visibility prop is not given to other users.
function isPublic({ visibility = '' } = {}) {
  return visibility !== 'PRIVATE'
}
function preferredContactInfo({ preferredUsages }) {
  return preferredUsages?.includes('CONTACT_CARD')
}
function isContactType(type) {
  return ({ method }) => method === type
}
function getContactMethods({ contactInfo }) {
  const methods = contactInfo?.methods.filter(isPublic)
  const emails = methods?.filter(isContactType('EMAIL')) || []
  const phoneNumbers = methods?.filter(isContactType('PHONE')) || []
  const email = emails.filter(preferredContactInfo)[0]?.value || emails[0]?.value
  const phoneNumber = phoneNumbers.filter(preferredContactInfo)[0]?.value || phoneNumbers[0]?.value
  return { email, phoneNumber }
}
function getPublicLocationNames({ location = {} }) {
  const { stateOrProvince, country } = location
  const countryName = country && isPublic(country) && country?.name
  const stateOrProvinceName = stateOrProvince && isPublic(stateOrProvince) && stateOrProvince?.name
  return { countryName, stateOrProvinceName }
}

function formulateState({ userProfile, portraitUrl, userLoading, userProfileLoading, cisId, hasError }) {
  if (hasError) {
    return { error: true }
  }
  // If there isn't a cis id, the contact is loading.
  // If the cisId and the userProfile cisId don't match it might be because the user profile is for the current user (because there wasn't a cisid and it's a hook)
  if (userLoading || userProfileLoading || !cisId || cisId !== userProfile.cisId) {
    return { contactLoading: true }
  }
  if (userProfile.cisId?.includes('cis.wkca')) {
    return userProfile
  }
  const { countryName, stateOrProvinceName } = getPublicLocationNames(userProfile)
  const { email, phoneNumber } = getContactMethods(userProfile)
  return {
    cisId: userProfile.cisId,
    cpUserId: userProfile.cpUserId,
    portraitUrl: userProfile.portrait?.links?.thumb200sUri
      ? `${userProfile.portrait?.links?.thumb200sUri}?sessionId=${getSessionId()}`
      : portraitUrl,
    contactName: userProfile.name.value,
    contactId: userProfile.contactId?.value,
    countryName,
    stateOrProvinceName,
    email,
    phoneNumber,
  }
}

export default function useContactData({
  passedInContactData,
  portraitUrl,
  overlay = { close: () => {} },
  hideErrorStatusOverlay = false,
}) {
  const { signedIn, userLoading } = useUser()
  const { cisId: passedInCisId, cpUserId } = passedInContactData
  debug('CisId or cpUserId passed in:', passedInCisId || cpUserId)
  const [cisId, setCisId] = useState(passedInContactData.cisId)
  const showErrorMessage = useContactError()
  const { userProfile, userProfileLoading, error: userProfileError } = useUserProfile(cisId)
  const { close: closeOverlay } = overlay
  const [getCisIdFromCpUserIdError, setGetCisIdFromCpUserIdError] = useState(false)
  const cpUserIdRef = useRef()

  useEffect(() => {
    async function getCisId() {
      try {
        debug(`Fetching cisId with id: ${cpUserId}`)
        const theCisId = await getCisIdFromCpUserId(cpUserId)
        setCisId(theCisId)
      } catch (error) {
        setGetCisIdFromCpUserIdError(true)
      }
    }
    if (passedInCisId) {
      setCisId(passedInCisId)
    } else if (signedIn && cpUserId !== cpUserIdRef.current) {
      cpUserIdRef.current = cpUserId
      getCisId()
    }
  }, [passedInCisId, cpUserId, signedIn])

  useEffect(() => {
    if (getCisIdFromCpUserIdError || userProfileError) {
      !hideErrorStatusOverlay && showErrorMessage()
      setTimeout(() => {
        closeOverlay()
      })
    }
  }, [getCisIdFromCpUserIdError, userProfileError, showErrorMessage, closeOverlay, hideErrorStatusOverlay])

  return formulateState({
    userProfile,
    portraitUrl,
    userLoading,
    userProfileLoading,
    cisId,
    hasError: getCisIdFromCpUserIdError || userProfileError,
  })
}
