import React, { lazy, Suspense } from 'react'
import { css } from '@linaria/core'
import { QuickGlanceOverlay, useContainerWidth, Paragraph, colors, Separator } from '@fs/zion-ui'
import { useHelpee, useUser } from '@fs/zion-user'
import zionDebug from '@fs/zion-debug'
import { Trans } from 'react-i18next'
import { Link } from '@fs/zion-router'
import { useContactAnalytics, useIsSelf } from '../ContactHooks'
import { ContactPersonBlock, ContactInfo, ContactOverlayMinWidth } from './ContactOverlaySimpleViews'
import ContactRelationshipButton from './ContactRelationshipButton'
import AddRemoveContactButton from './AddRemoveContactButton'
import isFamilySearch from '../isFamilySearch'
import { useChatRestricted } from './useChatRestricted'

const FamilySearchOverlayContent = lazy(() => import('../FamilySearchOverlayContent'))
const ContactActionButton = lazy(() => import('./ContactActionButton'))

const debug = zionDebug('contactOverlay:view')

const chatDisableLinkCss = css`
  color: ${colors.blue70} !important;
  text-decoration: none;
`

const bottomCss = css`
  margin: 6px 10px;
`

function ContactOverlayView({
  overlay,
  contact,
  userProfile,
  portraitUrl: passedInPortraitUrl,
  disableRelationshipForStorybook = false,
  hideMessaging,
  onContactRemoved,
  chatRestrictedOverride,
  ...sendMessageButtonProps
}) {
  const user = useUser()
  const isSelf = useIsSelf(contact.cisId)
  debug(`Is own contact info: ${!!isSelf}`)
  // disable relationship viewing feature if helpee user exists
  // using useHelpee instead of isHelping for more fine grain control over components. (Don't start relationship component if is helper)
  const helpee = useHelpee()

  const atWidth = useContainerWidth()
  const isFamilySearchUser = isFamilySearch(contact?.cisId)
  useContactAnalytics(overlay)
  const { contactName } = contact || {}
  const contactRelationshipButtonProps = {
    overlay,
    contact,
    helpee,
    isSelf,
    disableRelationshipForStorybook,
    setRelationDisplay: () => {},
  }
  const contactActionButtonProps = {
    isSelf,
    helpee,
    contact,
    sendMessageButtonProps,
  }

  const { chatWithAnyoneRestricted, chatWithContactRestricted } = useChatRestricted(
    contact.cisId,
    chatRestrictedOverride
  )
  const hideContactInfo = chatWithAnyoneRestricted || chatWithContactRestricted
  const chatDisabledMessage = (
    <Trans i18nKey="contact-overlay.chat-disabled-message">
      Unable to message this user.
      <Link
        to="/help/helpcenter/article/familysearch-chat-frequently-asked-questions-faqs"
        className={chatDisableLinkCss}
        external
      >
        Learn more.
      </Link>
    </Trans>
  )

  if (isFamilySearchUser) {
    return (
      <QuickGlanceOverlay
        {...overlay}
        fullscreen
        autoFocus={overlay.transitioning || contact?.contactLoading ? false : contact}
      >
        <Suspense fallback="">
          <FamilySearchOverlayContent />
        </Suspense>
      </QuickGlanceOverlay>
    )
  }
  return (
    <>
      {user.signedIn && (
        <QuickGlanceOverlay
          {...overlay}
          fullscreen
          autoFocus={overlay.transitioning || contact?.contactLoading ? false : contact} // setting autoFocus to contact to ensure resetting of keyboard focus when contact changes
        >
          <ContactPersonBlock {...contact} />
          <ContactInfo {...contact} hideContactInfo={hideContactInfo}>
            <ContactRelationshipButton {...contactRelationshipButtonProps} />
            {contact.cisId && !isSelf && !hideContactInfo && (
              <AddRemoveContactButton
                {...contact}
                name={userProfile?.name?.value || contactName}
                onContactRemoved={onContactRemoved}
              />
            )}
          </ContactInfo>
          {atWidth({ default: null, sm: <ContactOverlayMinWidth /> })}

          {!((hideMessaging && !isSelf) || chatWithAnyoneRestricted) && (
            <div className={bottomCss}>
              <Suspense fallback="">
                <ContactActionButton {...contactActionButtonProps} disabled={chatWithContactRestricted} />
              </Suspense>
              <Separator size="nano" />
              {!isSelf && chatWithContactRestricted && (
                <Paragraph size="xs" centered>
                  {chatDisabledMessage}
                </Paragraph>
              )}
            </div>
          )}
        </QuickGlanceOverlay>
      )}
    </>
  )
}

export default ContactOverlayView
