import { useEffect, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { i18n } from '@fs/zion-locale'

export default function useSetRelationshipDescriptionAndPortrait({
  userHasNotOptedIn,
  closeRelative,
  noRelationship,
  relationshipDescription,
  targetPerson,
}) {
  const { t } = useTranslation()
  const [relationshipDescriptionString, setRelationshipDescriptionString] = useState()
  const [portraitUrl, setPortraitUrl] = useState()

  useEffect(() => {
    setRelationshipDescriptionString(getDescriptionString())
    function getDescriptionString() {
      // Set status that controls the relationship string below the contact's name.
      if (userHasNotOptedIn === false) return t('relation-view.unavailable', 'Relationship Not Available')
      if (closeRelative) return t('relation-view.close', 'Close relationship')
      if (noRelationship) return t('relation-view.not-related', 'Not related')
      // the end point to get the relationship only displays the description in english and spanish.
      if (!noRelationship && ['en', 'es'].includes(i18n.language)) return relationshipDescription
      return ''
    }
  }, [userHasNotOptedIn, closeRelative, noRelationship, relationshipDescription, t])

  useEffect(() => {
    if (targetPerson?.portraitUrl) {
      setPortraitUrl(targetPerson.portraitUrl)
    }
  }, [targetPerson])

  return [relationshipDescriptionString, portraitUrl]
}
