import React, { useEffect, useState, useRef, useCallback } from 'react'
import { useIsHelping } from '@fs/zion-user'
import { useTranslation } from 'react-i18next'
import { PersonAdd, PersonRemove, ContentCheck } from '@fs/zion-icon'
import { ListItem, useStatusOverlay, Ellipsis } from '@fs/zion-ui'
import { addContact, removeContact, getFriendsIds } from '@fs/zion-relationship-service'
import { boolAttr } from '@fs/zion-frontend-friends'
import { track } from '../../ContactHooks'

export default function AddRemoveContactButton({ cisId, name, onContactRemoved = () => {} }) {
  const { t } = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const [isContact, setIsContact] = useState(null)
  const isHelping = useIsHelping()
  const mounted = useRef(false)

  useEffect(() => {
    mounted.current = true
    return () => {
      mounted.current = false
    }
  })

  useEffect(() => {
    async function detectIfIsContact() {
      setIsContact(false)
      const friendsList = await getFriendsIds()
      if (friendsList && mounted.current) {
        setIsContact(friendsList.includes(cisId))
      }
    }
    if (cisId && isContact !== true && isContact !== false) {
      detectIfIsContact()
    }
  }, [cisId, isContact])

  const showErrorMessage = useCallback(
    ({ message }) => {
      showStatusOverlay({
        message,
        Icon: ContentCheck,
        dismissable: true,
        transient: true,
      })
    },
    [showStatusOverlay]
  )

  const handleAddContact = useCallback(async () => {
    try {
      await addContact(cisId)
      setIsContact(true)
      showStatusOverlay({
        message: t('contact-overlay.contact-added', 'Contact Added Successfully'),
        Icon: ContentCheck,
        dismissable: true,
        transient: true,
        actionLabel: t('contact-overlay.view-contact', 'View Contacts'),
        actionCallback: () => {
          track('viewContacts:clicked')
          window.location.href = '/connect/contacts'
        },
      })
    } catch (error) {
      showErrorMessage({
        message: t('contact-overlay.contact-add-error', 'There was a problem adding the Contact. Try again later.'),
      })
    }
  }, [cisId, showErrorMessage, t, showStatusOverlay])

  const handleRemoveContact = useCallback(async () => {
    try {
      await removeContact(cisId)
      onContactRemoved()
      setIsContact(false)
      showStatusOverlay({
        message: t('contact-overlay.contact-removed', 'Contact Removed Successfully'),
        Icon: ContentCheck,
        dismissable: true,
        transient: true,
        actionLabel: t('undo', 'UNDO'),
        actionCallback: () => {
          track('undoRemoveFriend:clicked')
          handleAddContact()
        },
      })
    } catch (error) {
      showErrorMessage({
        message: t(
          'contact-overlay.contact-remove-error',
          'There was a problem removing the Contact. Try again later.'
        ),
      })
    }
  }, [cisId, showErrorMessage, t, showStatusOverlay, handleAddContact, onContactRemoved])

  return (
    <>
      {isContact ? (
        <ListItem
          onClick={(event) => {
            track('removeFriend:clicked', event.target)
            handleRemoveContact()
          }}
          primaryText={<Ellipsis>{t('contact-overlay.remove-contact', 'Remove Contact')}</Ellipsis>}
          startElement={<ListItem.Icon Icon={PersonRemove} />}
          aria-label={t('contact-overlay.remove-contact.a11y', 'click to remove {name} from contacts', { name })}
          disable={boolAttr(isHelping)}
        />
      ) : (
        <ListItem
          onClick={(event) => {
            track('addFriend:clicked', event.target)
            handleAddContact()
          }}
          primaryText={<Ellipsis>{t('contact-overlay.add-contact', 'Add Contact')}</Ellipsis>}
          startElement={<ListItem.Icon Icon={PersonAdd} />}
          aria-label={t('contact-overlay.add-contact.a11y', 'click to add {name} to contacts', { name })}
          disable={boolAttr(isHelping)}
        />
      )}
    </>
  )
}
